import{_ as i,c as a,o as t,aj as e}from"./chunks/framework.guNMSiFm.js";const c=JSON.parse('{"title":"Troubleshooting Integration Issues","description":"","frontmatter":{},"headers":[],"relativePath":"help/integration-issues.md","filePath":"help/integration-issues.md","lastUpdated":1777621302000}'),n={name:"help/integration-issues.md"};function h(l,s,r,p,o,k){return t(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="troubleshooting-integration-issues" tabindex="-1">Troubleshooting Integration Issues <a class="header-anchor" href="#troubleshooting-integration-issues" aria-label="Permalink to &quot;Troubleshooting Integration Issues&quot;">​</a></h1><p>This section offers troubleshooting tips for issues with Iroha 2 and Iroha 3 integration. If the issue you are experiencing is not described here, contact us via <a href="https://t.me/hyperledgeriroha" target="_blank" rel="noreferrer">Telegram</a>.</p><h2 id="client-cannot-connect" tabindex="-1">Client cannot connect <a class="header-anchor" href="#client-cannot-connect" aria-label="Permalink to &quot;Client cannot connect&quot;">​</a></h2><p>Check that the client config points to the peer&#39;s Torii address:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">torii_url = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:8080/&quot;</span></span></code></pre></div><p>For CLI checks, pass the same file explicitly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/client.toml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span></span></code></pre></div><p>If the peer runs in Docker or Kubernetes, use the host or service address that is reachable from the client process. <code>127.0.0.1</code> inside a container is not the host machine.</p><p>For public Taira tests, start with an unsigned endpoint probe:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://taira.sora.org/status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{blocks, txs_approved, txs_rejected, queue_size, peers}&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://taira.sora.org/v1/domains?limit=5&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.items[].id&#39;</span></span></code></pre></div><p>If these commands fail with <code>502</code>, TLS, DNS, or timeout errors, fix network reachability or wait for the public testnet endpoint before debugging account keys or transaction payloads.</p><h2 id="transactions-are-rejected" tabindex="-1">Transactions are rejected <a class="header-anchor" href="#transactions-are-rejected" aria-label="Permalink to &quot;Transactions are rejected&quot;">​</a></h2><p>Most transaction failures are caused by identity or authorization mismatch:</p><ul><li>the account public key in the client config does not match the private key used for signing</li><li>the account is not registered in genesis or by a prior transaction</li><li>the account lacks the permission token or role required by the runtime validator</li><li>object IDs use old Iroha 2-era forms instead of current canonical forms such as <code>domain.dataspace</code></li></ul><p>Use <code>--output-format text</code> while debugging CLI commands so errors are easier to read:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/client.toml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> text</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transaction</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --msg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello&quot;</span></span></code></pre></div><h2 id="queries-return-empty-results" tabindex="-1">Queries return empty results <a class="header-anchor" href="#queries-return-empty-results" aria-label="Permalink to &quot;Queries return empty results&quot;">​</a></h2><p>Empty query results do not always mean the query failed. Check:</p><ul><li>the transaction that should create the object was committed</li><li>the queried domain, asset definition, or account ID is canonical</li><li>pagination or filters are not excluding the expected row</li><li>the client is connected to the intended network, not another localnet</li></ul><p>For domain checks, start with the broadest query:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/client.toml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span></span></code></pre></div><h2 id="event-or-block-streams-stop-early" tabindex="-1">Event or block streams stop early <a class="header-anchor" href="#event-or-block-streams-stop-early" aria-label="Permalink to &quot;Event or block streams stop early&quot;">​</a></h2><p>Block and event stream examples rely on Torii streaming endpoints. Verify the peer is still running, then test with a timeout:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/client.toml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blocks</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timeout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 30s</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/client.toml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> events</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> block</span></span></code></pre></div><p>For HTTP integrations, compare your endpoint paths with the current <a href="/iroha-2-docs/reference/torii-endpoints.html">Torii endpoint reference</a>.</p>`,25)])])}const F=i(n,[["render",h]]);export{c as __pageData,F as default};
